def first_missing_positive(xs):
    if not xs:
        return 1

    n = len(xs)
    for i in range(n):
        while 1 <= xs[i] <= n and xs[xs[i] - 1] != xs[i]:
            xs[xs[i] - 1], xs[i] = xs[i], xs[xs[i] - 1]

    for i in range(n):
        if xs[i] != i + 1:
            return i + 1
    return n + 1
